import { Bot } from 'grammy';

const token = process.env.BOT_TOKEN;
if (!token) throw new Error('BOT_TOKEN missing');

const bot = new Bot(token);

bot.command('start', (ctx) => ctx.reply('Salom! Bot ishga tushdi.'));
bot.on('message:text', (ctx) => ctx.reply(`Siz yozdingiz: ${ctx.message.text}`));

bot.start();

bot.use(async (ctx, next) => {
  const started = Date.now();
  try {
    await next();
  } catch (err) {
    console.error('bot_error', err);
    await ctx.reply('Kutilmagan xato. Keyinroq urinib ko‘ring.');
  } finally {
    console.log({ update: ctx.update.update_id, ms: Date.now() - started });
  }
});

bot.command('help', (ctx) => ctx.reply('/start, /help, /profile'));

bot.command('menu', async (ctx) => {
  await ctx.reply('Bo‘limni tanlang:', {
    reply_markup: {
      inline_keyboard: [
        [{ text: 'Profil', callback_data: 'menu:profile' }],
        [{ text: 'Buyurtma', callback_data: 'menu:order' }],
      ],
    },
  });
});

bot.callbackQuery('menu:profile', (ctx) => ctx.answerCallbackQuery({ text: 'Profil ochildi' }));

